148	        protected override void OnParametersSet()
149	        {
150	            base.OnParametersSet();
151	            if (Items != null)
152	            {
153	                if (ServerData != null)
154	                {
155	                    throw new InvalidOperationException(
156	                        $"{GetType()} can only accept one item source from its parameters. " +
157	                        $"Do not supply both '{nameof(Items)}' and '{nameof(ServerData)}'.");
158	                }
159	                if (VirtualizeServerData != null)
160	                {
161	                    throw new InvalidOperationException(
162	                        $"{GetType()} can only accept one item source from its parameters. " +
163	                        $"Do not supply both '{nameof(Items)}' and '{nameof(VirtualizeServerData)}'.");
164	                }
165	                return;
166	            }
167	
168	            if (VirtualizeServerData != null)
169	            {
170	                if (ServerData != null)
171	                {
172	                    throw new InvalidOperationException(
173	                        $"{GetType()} can only accept one item source from its parameters. " +
174	                        $"Do not supply both '{nameof(VirtualizeServerData)}' and '{nameof(ServerData)}'.");
175	                }
176	                if (QuickFilter != null)
177	                {
178	                    throw new InvalidOperationException(
179	                        $"Do not supply both '{nameof(VirtualizeServerData)}' and '{nameof(QuickFilter)}'.");
180	                }
181	                return;
182	            }
183	
184	            if (ServerData != null && QuickFilter != null)
185	            {
186	                throw new InvalidOperationException(
187	                    $"Do not supply both '{nameof(ServerData)}' and '{nameof(QuickFilter)}'.");
188	            }
189	        }
