792	        private void SetupCollectionChangeTracking()
793	        {
794	            if (Items is INotifyCollectionChanged changed)
795	            {
796	                changed.CollectionChanged += (s, e) =>
797	                {
798	                    InvokeAsync(async () =>
799	                    {
800	                        _currentRenderFilteredItemsCache = null;
801	
802	                        if (Groupable)
803	                            GroupItems();
804	
805	                        ApplyInitialExpansionForNewItems(e);
806	                        await CleanupRemovedItemsAsync(e);
807	                        StateHasChanged();
808	                    });
809	                };
810	            }
811	        }
