813	        private async Task CleanupRemovedItemsAsync(NotifyCollectionChangedEventArgs e)
814	        {
815	            if (e.Action == NotifyCollectionChangedAction.Reset)
816	            {
817	                // For reset, check all items in selection against the current items
818	                await CleanupStaleSelectionsAsync();
819	                CleanupStaleHierarchyExpansions();
820	                return;
821	            }
822	
823	            if (e.OldItems is null)
824	                return;
825	
826	            // Build a set of removed items for efficient lookup
827	            var removedItems = new HashSet<T>(e.OldItems.Cast<T>(), Comparer);
828	
829	            // Directly check removed items against selection (more efficient for small removals)
830	            var (selectionChanged, selectedItemChanged) = PruneSelectionFromRemovedItems(removedItems);
831	
832	            // Handle SelectedItem reset if needed
833	            if (selectedItemChanged)
834	            {
835	                await _selectedItemState.SetValueAsync(default);
836	            }
837	
838	            // Clean up hierarchy expansions for removed items
839	            PruneHierarchyExpansions(removedItems);
840	
841	            if (selectionChanged)
842	            {
843	                await FireSelectionChangedEventsAsync();
844	            }
845	        }
846	
847	        private async Task CleanupStaleSelectionsAsync()
848	        {
849	            if (Selection.Count == 0 && _selectedItemState.Value is null)
850	                return;
851	
852	            var currentItems = BuildCurrentItemsSet();
853	            var (selectionChanged, selectedItemChanged) = PruneSelectionAndSelectedItem(currentItems);
854	
855	            if (!selectionChanged && !selectedItemChanged)
856	                return;
857	
858	            if (selectedItemChanged)
859	            {
860	                await _selectedItemState.SetValueAsync(default);
861	            }
862	
863	            if (selectionChanged)
864	            {
865	                await FireSelectionChangedEventsAsync();
866	            }
867	        }
868	
869	        private void CleanupStaleHierarchyExpansions()
870	        {
871	            if (_openHierarchies.Count == 0 && _initialExpansions.Count == 0)
872	                return;
873	
874	            var currentItems = BuildCurrentItemsSet();
875	            PruneHierarchyExpansionsFromCurrentItems(currentItems);
876	        }
