878	        /// <summary>
879	        /// Builds a HashSet of current items from the data source.
880	        /// </summary>
881	        private HashSet<T> BuildCurrentItemsSet()
882	        {
883	            return Items is not null ? new HashSet<T>(Items, Comparer) : new HashSet<T>(Comparer);
884	        }
885	
886	        /// <summary>
887	        /// Removes items from Selection that are not present in currentItems.
888	        /// Returns a tuple indicating whether Selection changed and whether SelectedItem needs to be reset.
889	        /// </summary>
890	        private (bool SelectionChanged, bool SelectedItemChanged) PruneSelectionAndSelectedItem(HashSet<T> currentItems)
891	        {
892	            var selectionChanged = Selection.RemoveWhere(s => !currentItems.Contains(s)) > 0;
893	
894	            // Check if SelectedItem needs to be reset
895	            var selectedItemChanged = _selectedItemState.Value is not null && !currentItems.Contains(_selectedItemState.Value);
896	
897	            return (selectionChanged, selectedItemChanged);
898	        }
899	
900	        /// <summary>
901	        /// Removes items from Selection that are present in removedItems.
902	        /// More efficient when a small number of items are removed from a large collection.
903	        /// </summary>
904	        private (bool SelectionChanged, bool SelectedItemChanged) PruneSelectionFromRemovedItems(HashSet<T> removedItems)
905	        {
906	            var selectionChanged = false;
907	            foreach (var item in removedItems)
908	            {
909	                if (Selection.Remove(item))
910	                {
911	                    selectionChanged = true;
912	                }
913	            }
914	
915	            // Check if SelectedItem needs to be reset
916	            var selectedItemChanged = _selectedItemState.Value is not null && removedItems.Contains(_selectedItemState.Value);
917	
918	            return (selectionChanged, selectedItemChanged);
919	        }
920	
921	        /// <summary>
922	        /// Removes items from _openHierarchies and _initialExpansions that are present in the removedItems set.
923	        /// Used when specific items are removed from the collection.
924	        /// </summary>
925	        private void PruneHierarchyExpansions(HashSet<T> removedItems)
926	        {
927	            _openHierarchies.ExceptWith(removedItems);
928	            _initialExpansions.ExceptWith(removedItems);
929	        }
930	
931	        /// <summary>
932	        /// Removes items from _openHierarchies and _initialExpansions that are not present in currentItems.
933	        /// Used when checking against the full current items set.
934	        /// </summary>
935	        private void PruneHierarchyExpansionsFromCurrentItems(HashSet<T> currentItems)
936	        {
937	            _openHierarchies.RemoveWhere(h => !currentItems.Contains(h));
938	            _initialExpansions.RemoveWhere(e => !currentItems.Contains(e));
939	        }
