951	        private void ApplyInitialExpansionForNewItems(NotifyCollectionChangedEventArgs e)
952	        {
953	            if (_initialExpandedFunc is null || e.NewItems is null)
954	                return;
955	
956	            foreach (T item in e.NewItems)
957	            {
958	                if (_initialExpandedFunc.Invoke(item) && _initialExpansions.Add(item))
959	                {
960	                    _openHierarchies.Add(item);
961	                }
962	            }
963	        }
964	
965	        private void ApplyInitialExpansionForItems(IEnumerable<T>? items)
966	        {
967	            if (_initialExpandedFunc is null || items is null)
968	                return;
969	
970	            foreach (var item in items)
971	            {
972	                if (_initialExpandedFunc.Invoke(item) && _initialExpansions.Add(item))
973	                {
974	                    _openHierarchies.Add(item);
975	                }
976	            }
977	        }
