1398	            get
1399	            {
1400	                if (_currentRenderFilteredItemsCache != null) return _currentRenderFilteredItemsCache;
1401	                var items = HasServerData
1402	                    ? _serverData.Items
1403	                    : Items;
1404	
1405	                items ??= Enumerable.Empty<T>();
1406	
