1614	        internal async Task InvokeServerLoadFunc()
1615	        {
1616	            if (!HasServerData)
1617	                return;
1618	
1619	            if (VirtualizeServerData != null)
1620	            {
1621	                if (_mudVirtualize != null)
1622	                {
1623	                    // Cancel any prior request
1624	                    CancelServerDataToken();
1625	                    await _mudVirtualize.RefreshDataAsync();
1626	                }
1627	                else
1628	                {
1629	                    Loading = true;
1630	                    StateHasChanged();
1631	
1632	                    var state = new GridStateVirtualize<T>
1633	                    {
1634	                        StartIndex = 0,
1635	                        Count = 1,
1636	                        SortDefinitions = SortDefinitions.Values.OrderBy(sd => sd.Index).ToList(),
1637	                        // Additional ToList() here to decouple clients from internal list avoiding runtime issues
1638	                        FilterDefinitions = FilterDefinitions.ToList()
1639	                    };
1640	
1641	                    // Cancel any prior request
1642	                    CancelServerDataToken();
1643	
1644	                    Debug.Assert(_serverDataCancellationTokenSource is not null);
1645	                    _serverData = await VirtualizeServerData(state, _serverDataCancellationTokenSource.Token);
1646	                    _currentRenderFilteredItemsCache = null;
1647	
1648	                    Loading = false;
1649	                }
1650	            }
1651	            else
1652	            {
1653	                Loading = true;
1654	                StateHasChanged();
1655	
1656	                var state = new GridState<T>
1657	                {
1658	                    Page = CurrentPage,
1659	                    PageSize = RowsPerPage,
1660	                    SortDefinitions = SortDefinitions.Values.OrderBy(sd => sd.Index).ToList(),
1661	                    // Additional ToList() here to decouple clients from internal list avoiding runtime issues
1662	                    FilterDefinitions = FilterDefinitions.ToList()
1663	                };
1664	
1665	                // Cancel any prior request
1666	                CancelServerDataToken();
1667	
1668	                Debug.Assert(ServerData is not null);
1669	                Debug.Assert(_serverDataCancellationTokenSource is not null);
1670	                _serverData = await ServerData(state, _serverDataCancellationTokenSource.Token);
1671	                _currentRenderFilteredItemsCache = null;
1672	
1673	                if (CurrentPage * RowsPerPage > _serverData.TotalItems)
1674	                    CurrentPage = 0;
1675	
1676	                Loading = false;
1677	                PagerStateHasChangedEvent?.Invoke();
1678	            }
1679	            // handle initial hierarchy expansion
1680	            if (_initialExpandedFunc is not null)
1681	            {
1682	                foreach (var data in _serverData.Items)
1683	                {
1684	                    // ensure we only add it once if they were expanded initially
1685	                    if (_initialExpandedFunc(data) && _initialExpansions.Add(data))
1686	                    {
1687	                        _openHierarchies.Add(data);
1688	                    }
1689	                }
1690	            }
1691	
1692	            StateHasChanged();
1693	            GroupItems();
1694	        }
