1927	        internal IEnumerable<T> Sort(IEnumerable<T> items)
1928	        {
1929	            if (!items.Any())
1930	                return items;
1931	
1932	            if (null == SortDefinitions || 0 == SortDefinitions.Count)
1933	                return items;
1934	
1935	            IOrderedEnumerable<T>? orderedEnumerable = null;
1936	
1937	            foreach (var sortDefinition in SortDefinitions.Values.Where(sd => sd.SortFunc != null).OrderBy(sd => sd.Index))
1938	            {
1939	                Debug.Assert(sortDefinition.SortFunc is not null);
1940	                if (null == orderedEnumerable)
1941	                    orderedEnumerable = sortDefinition.Descending ? items.OrderByDescending(item => sortDefinition.SortFunc(item), sortDefinition.Comparer)
1942	                        : items.OrderBy(item => sortDefinition.SortFunc(item), sortDefinition.Comparer);
1943	                else
1944	                    orderedEnumerable = sortDefinition.Descending ? orderedEnumerable.ThenByDescending(item => sortDefinition.SortFunc(item), sortDefinition.Comparer)
1945	                        : orderedEnumerable.ThenBy(item => sortDefinition.SortFunc(item), sortDefinition.Comparer);
1946	            }
1947	
1948	            return orderedEnumerable ?? items;
1949	        }
