2364	        {
2365	            if (!noStateChange)
2366	                DropContainerHasChanged();
2367	
2368	            _groupDefinition = default;
2369	
2370	            // get all columns that have Groupable set to true
2371	            var groupedColumns = RenderedColumns.Where(x => x.groupable).ToList();
2372	            // is groupable on either DataGrid level or column level
2373	            var isGroupable = Groupable || groupedColumns.Count > 0;
2374	            // any columns that are groupable and have grouping set to true
2375	            groupedColumns = [.. groupedColumns.Where(x => x.GroupingState.Value).OrderBy(x => x._groupByOrderState.Value)];
2376	            // it's only groupable if a column can be grouped
2377	            isGroupable = isGroupable && groupedColumns.Count > 0;
2378	
2379	            if (!isGroupable || GetFilteredItemsCount() == 0)
2380	            {
2381	                if (_isFirstRendered && !noStateChange)
2382	                    StateHasChanged();
2383	                return;
2384	            }
2385	
2386	            // Initialize with the first group definition
2387	            _groupDefinition = ProcessGroup(groupedColumns[0]);
2388	
2389	            // Create a reference to build the hierarchy
2390	            var currentGroupDef = _groupDefinition;
2391	
2392	            // Start from index 1 since we've already processed the first column
2393	            for (var i = 1; i < groupedColumns.Count; i++)
2394	            {
2395	                var nextGroupDef = ProcessGroup(groupedColumns[i]);
2396	                // Connect it to the current level
2397	                currentGroupDef.InnerGroup = nextGroupDef;
2398	                // Move to the next level for the next iteration
2399	                currentGroupDef = nextGroupDef;
2400	            }
2401	
2402	            if ((_isFirstRendered || HasServerData) && !noStateChange)
2403	                StateHasChanged();
2404	        }
