2450	            foreach (var group in groups)
2451	            {
2452	                var expanded = false;
2453	                var currentKeyPath = groupDef.Parent?.KeyPath.ToList() ?? [];
2454	                GroupKeyPath? keyPath = null;
2455	                if (group is not null)
2456	                {
2457	                    currentKeyPath.Add(group.Key);
2458	                    keyPath = new GroupKeyPath(currentKeyPath);
2459	                    var key = new GroupKey(groupDef.Title, keyPath);
2460	                    expanded = _groupExpansionsDict.TryGetValue(key, out var value) ? value :
2461	                                   groupDef.Expanded;
2462	                    _groupExpansionsDict.TryAdd(key, expanded);
2463	                }
2464	                var newGroupDefinition = new GroupDefinition<T>
2465	                {
2466	                    DataGrid = this,
2467	                    Selector = groupDef.Selector,
2468	                    Expanded = expanded,
2469	                    GroupTemplate = groupDef.GroupTemplate,
2470	                    Indentation = groupDef.Indentation,
2471	                    Title = groupDef.Title,
2472	                    Parent = groupDef.Parent,
2473	                    Grouping = group ?? new EmptyGrouping<object?, T>(null),
2474	                    KeyPath = keyPath ?? new GroupKeyPath(currentKeyPath),
2475	                };
2476	
2477	                var innerGroup = groupDef.InnerGroup;
2478	                if (innerGroup != null)
2479	                {
2480	                    // Create a new InnerGroup instance to prevent unwanted side effects from shared references at different grouping levels (e.g., tracking the Expanded state)
2481	                    newGroupDefinition.InnerGroup = new GroupDefinition<T>
2482	                    {
2483	                        DataGrid = this,
