2488	                        Title = innerGroup.Title,
2489	                        Parent = newGroupDefinition,
2490	                        Grouping = innerGroup.Grouping,
2491	                        KeyPath = new GroupKeyPath(innerGroup.KeyPath),
2492	                        InnerGroup = innerGroup.InnerGroup
2493	                    };
2494	                }
2495	                result.Add(newGroupDefinition);
2496	            }
2497	            return result;
2498	        }
