2500	        internal async Task UpdateGroupingOrder(Column<T> column, bool added)
2501	        {
2502	            // if added then add to the end if no _groupByOrderState.Value
2503	            if (added)
2504	            {
2505	                var groupedColumns = RenderedColumns.Where(x => x.GroupingState.Value && x != column);
2506	                var newOrder = groupedColumns.Any() ? groupedColumns.Max(x => x._groupByOrderState.Value) + 1 : 0;
2507	                await column._groupByOrderState.SetValueAsync(newOrder);
2508	            }
2509	            // if removed then reset _groupByOrderState.Value
2510	            else
2511	            {
2512	                await column._groupByOrderState.SetValueAsync(default);
2513	            }
2514	            // expand all but last grouped column when changed
2515	            await GroupExpansion();
2516	        }
2517	
2518	        private async Task GroupExpansion()
2519	        {
2520	            var groupedColumns = RenderedColumns.Where(x => x.GroupingState.Value).OrderBy(x => x._groupByOrderState.Value).SkipLast(1);
2521	            foreach (var col in groupedColumns.OrderBy(x => x._groupByOrderState.Value))
2522	            {
2523	                await col._groupExpandedState.SetValueAsync(true);
2524	            }
2525	        }
2526	
2527	        /// <summary>
2528	        /// Toggles the expanded or collapsed state of the specified group by column name and key.
2529	        /// </summary>
2530	        /// <param name="columnName">The name of the grouped column.</param>
2531	        /// <param name="key">The group key identifying the specific group to expand or collapse.</param>
2532	        /// <param name="expanded">Whether the group should be expanded (true) or collapsed (false).</param>
2533	        public void ToggleGroupExpand(string? columnName, object? key, bool expanded)
2534	        {
2535	            var groupKey = new GroupKey(columnName, key);
2536	
2537	            // update the expansion state for _groupExpansionsDict
2538	            // if it has a key we see if it differs from the definition Expanded State and update accordingly
2539	            // if it doesn't we add it if the new state doesn't match the definition
2540	            var col = RenderedColumns.FirstOrDefault(x => x.PropertyName == columnName);
2541	            if (expanded == col?._groupExpandedState.Value)
2542	                _groupExpansionsDict.Remove(groupKey);
2543	            else
2544	                _groupExpansionsDict[groupKey] = expanded;
2545	
2546	            _groupInitialExpanded = false;
2547	            StateHasChanged();
2548	        }
2549	
2550	        /// <summary>
2551	        /// Expands all groups async.
2552	        /// </summary>
2553	        /// <remarks>
2554	        /// Applies when <see cref="Groupable"/> is <c>true</c>.
2555	        /// </remarks>
2556	        public async Task ExpandAllGroupsAsync()
2557	        {
2558	            if (_groupDefinition != null && _groupable)
2559	            {
2560	                await ToggleGroupExpandRecursively(true);
2561	            }
2562	        }
2563	
2564	        /// <summary>
2565	        /// Collapses all groups async.
2566	        /// </summary>
2567	        /// <remarks>
2568	        /// Applies when <see cref="Groupable"/> is <c>true</c>.
2569	        /// </remarks>
2570	        public async Task CollapseAllGroupsAsync()
2571	        {
2572	            if (_groupDefinition != null && _groupable)
2573	            {
2574	                await ToggleGroupExpandRecursively(false);
2575	            }
2576	        }
2577	
2578	        private async Task ToggleGroupExpandRecursively(bool expanded)
2579	        {
2580	            _groupExpansionsDict.Clear();
2581	            foreach (var column in RenderedColumns)
2582	            {
2583	                if (column.GroupingState.Value)
2584	                {
2585	                    await column._groupExpandedState.SetValueAsync(expanded);
2586	                }
2587	            }
2588	            _groupInitialExpanded = false;
2589	            GroupItems();
2590	        }
2591	
2592	        /// <summary>
2593	        /// Expands all Hierarchy columns
2594	        /// </summary>
2595	        public async Task ExpandAllHierarchy()
2596	        {
2597	            Debug.Assert(_buttonDisabledFunc is not null);
2598	            var expandedItems = FilteredItems.Where(x => !_buttonDisabledFunc(x) && _openHierarchies.Add(x));
2599	            foreach (var item in expandedItems)
2600	            {
2601	                await HierarchyVisibilityToggled.InvokeAsync(new(item, true));
2602	            }
2603	            await InvokeAsync(StateHasChanged);
2604	        }
2605	
2606	        /// <summary>
2607	        /// Collapses all Hierarchy columns
2608	        /// </summary>
2609	        public async Task CollapseAllHierarchy()
2610	        {
2611	            Debug.Assert(_buttonDisabledFunc is not null);
2612	            foreach (var openedHierarchy in _openHierarchies.Where(x => !_buttonDisabledFunc(x)).ToList())
2613	            {
2614	                await HierarchyVisibilityToggled.InvokeAsync(new(openedHierarchy, false));
2615	                _openHierarchies.Remove(openedHierarchy);
2616	            }
2617	            await InvokeAsync(StateHasChanged);
2618	        }
2619	
2620	        /// <summary>
2621	        /// Collapses or expands the hierarchy of the specified item.
2622	        /// </summary>
2623	        /// <param name="item">The item whose hierarchy visibility is to be toggled.</param>
2624	        public async Task ToggleHierarchyVisibilityAsync(T item)
2625	        {
2626	            // if ExpandSingleRow is true, clear all open hierarchies, which will immediately add the item that was clicked.
2627	            if (_expandSingleRowState.Value)
2628	            {
2629	                foreach (var openedHierarchy in _openHierarchies.Where(x => x != null && !x.Equals(item)))
2630	                {
2631	                    await HierarchyVisibilityToggled.InvokeAsync(new(openedHierarchy, false));
2632	                }
2633	                _openHierarchies.Clear();
2634	                _openHierarchies.Add(item);
2635	                await InvokeAsync(StateHasChanged);
2636	                return;
2637	            }
2638	
2639	            // if item doesn't exist remove will return false and add the item
2640	            if (!_openHierarchies.Remove(item))
2641	            {
2642	                _openHierarchies.Add(item);
2643	                await HierarchyVisibilityToggled.InvokeAsync(new(item, true));
2644	            }
2645	            else
2646	            {
2647	                await HierarchyVisibilityToggled.InvokeAsync(new(item, false));
2648	            }
2649	
2650	            await InvokeAsync(StateHasChanged);
2651	        }
2652	
2653	        #region Resize feature
2654	
2655	        internal bool IsResizing { get; set; }
2656	
2657	        private ElementReference _gridElement;
2658	
2659	        internal async Task<double> GetActualHeight()
2660	        {
2661	            var gridRect = await _gridElement.MudGetBoundingClientRectAsync();
2662	            var gridHeight = gridRect.Height;
2663	            return gridHeight;
2664	        }
2665	
2666	        #endregion
2667	
2668	        /// <summary>
2669	        /// Releases resources used by this data grid.
2670	        /// </summary>
2671	        public void Dispose()
2672	        {
2673	            Dispose(disposing: true);
2674	            GC.SuppressFinalize(this);
2675	        }
2676	
2677	        protected virtual void Dispose(bool disposing)
2678	        {
2679	            _serverDataCancellationTokenSource?.Dispose();
2680	        }
2681	
