        internal string GetGroupIcon(bool isExpanded, bool? rtl = null)
        {
            if (rtl == null)
                rtl = RightToLeft;
            if (isExpanded)
            {
                return Icons.Material.Filled.ExpandMore;
            }
            return rtl.Value ? Icons.Material.Filled.ChevronLeft : Icons.Material.Filled.ChevronRight;
