        [Test]
        public async Task DataGridCommittedItemChangedEventTest()
        {
            // This test verifies that CommittedItemChanged fires AFTER changes are applied to the source item
            var comp = Context.Render<DataGridCommittedItemChangedTest>();
            var dataGrid = comp.FindComponent<MudDataGrid<DataGridCommittedItemChangedTest.Item>>();
            var dataGridInstance = dataGrid.Instance;

            // Get the first item to edit
            var items = comp.Instance._items.ToList();
            var itemToEdit = items[0];
            var originalName = itemToEdit.Name;

            // Set up editing state using internal fields via reflection
            var editingSourceItemField = typeof(MudDataGrid<DataGridCommittedItemChangedTest.Item>)
                .GetField("_editingSourceItem", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
            var editingItemField = typeof(MudDataGrid<DataGridCommittedItemChangedTest.Item>)
                .GetField("_editingItem", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);

            editingSourceItemField!.SetValue(dataGridInstance, itemToEdit);

            // Create a modified clone
            var clonedItem = new DataGridCommittedItemChangedTest.Item("ModifiedName");
            editingItemField!.SetValue(dataGridInstance, clonedItem);

            // Create a simple MudForm that is valid (to bypass form validation)
            var formField = typeof(MudForm).GetField("_form", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
            var editFormField = typeof(MudDataGrid<DataGridCommittedItemChangedTest.Item>)
                .GetField("_editForm", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);

            var form = new MudForm();
            // Set _isValid to true via reflection
            var isValidField = typeof(MudForm).GetField("_lastValidationResult", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance) ??
                               typeof(MudForm).GetField("_isValid", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance) ??
                               typeof(MudForm).GetProperty("IsValid", System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance);

            // Let's use a different approach - just set _editForm and make the form valid
            editFormField!.SetValue(dataGridInstance, form);

            // Call CommitItemChangesAsync to trigger the commits
            var commitMethod = typeof(MudDataGrid<DataGridCommittedItemChangedTest.Item>)
                .GetMethod("CommitItemChangesAsync", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance, Type.EmptyTypes);
            await comp.InvokeAsync(() => commitMethod!.Invoke(dataGridInstance, null));

            // Verify CommittedItemChanges was called
            comp.Instance.CommittedItemChangesCalled.Should().BeTrue("CommittedItemChanges should be called");

            // Verify CommittedItemChanged was called
            comp.Instance.CommittedItemChangedCalled.Should().BeTrue("CommittedItemChanged should be called after changes are applied");

            // Verify that the source item was actually modified (changes applied before CommittedItemChanged)
            itemToEdit.Name.Should().Be("ModifiedName", "Source item should be updated with changes before CommittedItemChanged fires");

            // Verify that CommittedItemChanged received the updated source item
            comp.Instance.CommittedItemChangedName.Should().Be("ModifiedName", "CommittedItemChanged should receive the source item with applied changes");
        }

        #endregion
    }
}

